// ============================================================
// TOOL: LAUNCH META CAMPAIGN
// Crée une campagne Meta Ads réelle via Facebook Graph API
// ============================================================

const axios = require('axios');

// ⚠️ L'utilisateur doit configurer ses credentials Meta dans n8n
// Aller dans Settings > Credentials > New Credential > Meta for Business
// Ce code récupère automatiquement les credentials de l'utilisateur
const credentials = await this.getCredentials('metaApi');
const ACCESS_TOKEN = credentials.accessToken;
const AD_ACCOUNT_ID = credentials.adAccountId; // Format: act_XXXXXXXXX
const PAGE_ID = credentials.pageId;

if (!ACCESS_TOKEN || !AD_ACCOUNT_ID) {
  return {
    success: false,
    error: "⚠️ ERREUR: Credentials Meta non configurées. Va dans Settings > Credentials > New Credential > Meta for Business et configure ton Access Token et Ad Account ID."
  };
}

// Paramètres du tool
const {
  campaign_name,
  daily_budget,
  start_time,
  targeting_category = 'BROAD',
  creative_url,
  ad_copy,
  headline,
  cta = 'LEARN_MORE',
  user_approval = 'PENDING'
} = $input.json;

// ============================================================
// SÉCURITÉ: Vérifier l'approbation utilisateur
// ============================================================

if (user_approval !== 'GO') {
  return {
    success: false,
    requires_approval: true,
    preview: {
      campaign_name,
      daily_budget: `${daily_budget} USD`,
      targeting: targeting_category,
      creative_url,
      headline,
      ad_copy: ad_copy.substring(0, 100) + '...',
      estimated_monthly_spend: daily_budget * 30
    },
    message: `⚠️ APPROBATION REQUISE\n\nCampagne: ${campaign_name}\nBudget journalier: ${daily_budget} USD\nDépense mensuelle estimée: ${daily_budget * 30} USD\nCiblage: ${targeting_category}\nURL: ${creative_url}\nHeadline: ${headline}\n\n🚨 Pour lancer cette campagne, réponds avec: "GO"\n🛑 Pour annuler, réponds avec: "CANCEL"`
  };
}

// ============================================================
// ÉTAPE 1: Créer la Campaign
// ============================================================

const GRAPH_API = 'https://graph.facebook.com/v21.0';

let campaignId;
try {
  const campaignResponse = await axios.post(
    `${GRAPH_API}/${AD_ACCOUNT_ID}/campaigns`,
    {
      name: campaign_name,
      objective: 'OUTCOME_TRAFFIC', // Traffic vers site web
      status: 'PAUSED', // Démarrer en pause par sécurité
      special_ad_categories: []
    },
    {
      params: { access_token: ACCESS_TOKEN }
    }
  );

  campaignId = campaignResponse.data.id;
} catch (error) {
  return {
    success: false,
    step: 'CREATE_CAMPAIGN',
    error: error.response?.data?.error?.message || error.message
  };
}

// ============================================================
// ÉTAPE 2: Créer l'Ad Set (ciblage + budget)
// ============================================================

const targetingSpec = {
  geo_locations: { countries: ['US'] },
  ...(targeting_category === 'BROAD' ? {} : {
    interests: targeting_category === 'TECH' ? [{ id: '6003139266461', name: 'Technology' }] :
               targeting_category === 'MARKETING' ? [{ id: '6003020834693', name: 'Digital marketing' }] :
               {}
  })
};

let adSetId;
try {
  const adSetResponse = await axios.post(
    `${GRAPH_API}/${AD_ACCOUNT_ID}/adsets`,
    {
      name: `${campaign_name} - AdSet 1`,
      campaign_id: campaignId,
      billing_event: 'IMPRESSIONS',
      optimization_goal: 'LINK_CLICKS',
      daily_budget: Math.round(daily_budget * 100), // Convertir en cents
      start_time: start_time || new Date(Date.now() + 3600000).toISOString(), // Démarrer dans 1h par défaut
      targeting: targetingSpec,
      status: 'PAUSED'
    },
    {
      params: { access_token: ACCESS_TOKEN }
    }
  );

  adSetId = adSetResponse.data.id;
} catch (error) {
  return {
    success: false,
    step: 'CREATE_ADSET',
    error: error.response?.data?.error?.message || error.message,
    campaign_id: campaignId
  };
}

// ============================================================
// ÉTAPE 3: Créer l'Ad Creative
// ============================================================

let creativeId;
try {
  const creativeResponse = await axios.post(
    `${GRAPH_API}/${AD_ACCOUNT_ID}/adcreatives`,
    {
      name: `${campaign_name} - Creative`,
      object_story_spec: {
        page_id: PAGE_ID,
        link_data: {
          link: creative_url,
          message: ad_copy,
          name: headline,
          call_to_action: {
            type: cta
          }
        }
      }
    },
    {
      params: { access_token: ACCESS_TOKEN }
    }
  );

  creativeId = creativeResponse.data.id;
} catch (error) {
  return {
    success: false,
    step: 'CREATE_CREATIVE',
    error: error.response?.data?.error?.message || error.message,
    campaign_id: campaignId,
    adset_id: adSetId
  };
}

// ============================================================
// ÉTAPE 4: Créer l'Ad (liaison finale)
// ============================================================

let adId;
try {
  const adResponse = await axios.post(
    `${GRAPH_API}/${AD_ACCOUNT_ID}/ads`,
    {
      name: `${campaign_name} - Ad 1`,
      adset_id: adSetId,
      creative: { creative_id: creativeId },
      status: 'PAUSED' // Toujours démarrer en pause
    },
    {
      params: { access_token: ACCESS_TOKEN }
    }
  );

  adId = adResponse.data.id;
} catch (error) {
  return {
    success: false,
    step: 'CREATE_AD',
    error: error.response?.data?.error?.message || error.message,
    campaign_id: campaignId,
    adset_id: adSetId,
    creative_id: creativeId
  };
}

// ============================================================
// SUCCÈS: Campagne créée
// ============================================================

return {
  success: true,
  message: `✅ Campagne Meta Ads créée avec succès!\n\nCampagne: ${campaign_name}\nStatut: PAUSED (active manuellement dans Meta Ads Manager)\nBudget: ${daily_budget} USD/jour\n\n🔗 Voir dans Meta Ads Manager:\nhttps://business.facebook.com/adsmanager/manage/campaigns?act=${AD_ACCOUNT_ID.replace('act_', '')}&selected_campaign_ids=${campaignId}`,
  campaign_id: campaignId,
  adset_id: adSetId,
  creative_id: creativeId,
  ad_id: adId,
  dashboard_url: `https://business.facebook.com/adsmanager/manage/campaigns?act=${AD_ACCOUNT_ID.replace('act_', '')}&selected_campaign_ids=${campaignId}`
};

