// ============================================
// FORMAT UI RESPONSE
// Conforme au schema ui-response.schema.js
// ============================================

const aiResponse = $input.first().json;
const context = $('Prepare Trader Context').item.json;

// Extraire la reponse de l'IA
let traderDecisions;
try {
  let jsonStr = aiResponse.output || aiResponse.text || JSON.stringify(aiResponse);

  // Nettoyer les balises markdown si presentes
  jsonStr = jsonStr.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

  // Parser le JSON
  traderDecisions = JSON.parse(jsonStr);
} catch (e) {
  // Fallback avec decisions calculees manuellement
  const campaigns = context.market?.campaigns || [];
  const rules = context.rules || {};

  traderDecisions = {
    ui_component: 'CAMPAIGN_TABLE',
    dashboard: {
      snapshot_time: new Date().toISOString(),
      overall_health: 'WARNING',
      total_spend: context.market?.totals?.spend || 0,
      total_revenue: context.market?.totals?.revenue || 0,
      portfolio_roas: context.market?.totals?.portfolio_roas || 0
    },
    decisions: campaigns.map(c => {
      let action, actionEmoji, priority, reasoning;

      if (c.roas < (rules.stop_loss_threshold || 1.5)) {
        action = 'CUT';
        actionEmoji = '🛑';
        priority = 'HIGH';
        reasoning = `ROAS ${c.roas} < seuil ${rules.stop_loss_threshold || 1.5} - Hemorragie financiere`;
      } else if (c.roas > 5.0) {
        action = 'SCALE';
        actionEmoji = '🚀';
        priority = 'HIGH';
        reasoning = `ROAS ${c.roas} > 5.0 - Machine a cash, augmenter budget +20%`;
      } else {
        action = 'OPTIMIZE';
        actionEmoji = '⏸️';
        priority = 'MEDIUM';
        reasoning = `ROAS ${c.roas} en zone grise - Ajuster creatifs`;
      }

      return {
        campaign_id: c.id,
        campaign_name: c.name,
        current_roas: c.roas,
        current_spend: c.spend,
        current_revenue: c.revenue,
        action: action,
        action_emoji: actionEmoji,
        reasoning: reasoning,
        priority: priority
      };
    }),
    alerts: [
      {
        type: 'WARNING',
        message: 'Reponse IA parsee en fallback: ' + e.message
      }
    ]
  };
}

// Enrichir avec metadonnees V4
const uiResponse = {
  agent: 'TRADER',
  version: 'V4_CLOUD_NATIVE',
  timestamp: new Date().toISOString(),
  ...traderDecisions,
  _meta: {
    workflow: 'Trader MCP - Agency Killer V4',
    brand_id: context.brand_id,
    execution_id: $execution?.id || 'local'
  }
};

return [{ json: uiResponse }];
